func runLoaded(w *World, steps []ScriptStep, blob store.ItemY, stale map[string]bool, profile Profile, radius int) []MoveRow {
        applyWorld(w, blob)
        cache := &mem.CacheX{Obs: map[string]bool{}}
        mem.Merge(cache, blob)
        merged := mem.Snapshot(cache)
        for k, v := range stale {
                merged[k] = v
        }
