        moves := []MoveRow{}
        pastSave := false
        for _, step := range steps {
                if step.Action == "save" {
                        pastSave = true
                        continue
                }
                if !pastSave {
                        continue
                }
                w.Turn = step.Turn
                if step.Actor == "P" {
                        applyPlayer(w, step.Arg)
                        vis.ApplyLit(w, radius, blindNow(w))
                }
                if step.Actor == "H" {
                        moves = append(moves, advanceAll(w, merged)...)
                }
        }
        return moves
